async function main({ params }: Args): Promise<Output> {
    // 获取输入参数
    const { text, input1, input2 } = params; // 新增解构 input1 和 input2

    // 处理转义双引号
    const processedText = text.replace(/\\"/g, '"');

    // 按标点分割文本
    const segments = processedText.split(/[，。？]+/);

    // 过滤无效段落
    const filteredSegments = segments.filter(segment => {
        const trimmed = segment.trim();
        return trimmed !== '' && trimmed !== '"';
    });

    // 构建最终输出数组：前两位固定为 input1 和 input2
    const finalSegments = [];
    if (input1 !== undefined) finalSegments.push(input1); // 确保input1存在
    if (input2 !== undefined) finalSegments.push(input2); // 确保input2存在
    finalSegments.push(...filteredSegments); // 添加原文分割结果

    // 返回输出对象
    return {
        segments: finalSegments
    };
}
